#include <iostream>
using namespace std;

int main() {
    int a[5] = {10, 20, 30, 40, 50};
    cout << "正序: ";
    for (int i = 0; i < 5; i++) {
        cout << a[i] << " ";
    }
    cout << endl;
    cout << "逆序: ";
    for (int i = 4; i >= 0; i--) {
        cout << a[i] << " ";
    }
    cout << endl;
    cout << "相邻元素和: ";
    for (int i = 0; i < 4; i++) {
        cout << a[i] + a[i + 1] << " ";
    }
    cout << endl;
    return 0;
}

