#include <iostream>
#include <cstring>
using namespace std;

int main() {
    int a[10];
    memset(a, 0, sizeof(a));
    cout << "全0: ";
    for (int i = 0; i < 10; i++) cout << a[i] << " ";
    cout << endl;
    memset(a, -1, sizeof(a));
    cout << "全-1: ";
    for (int i = 0; i < 10; i++) cout << a[i] << " ";
    cout << endl;
    memset(a, 1, sizeof(a));
    cout << "memset 1: " << a[0] << " (不是1!)" << endl;
    return 0;
}

