using namespace std;

int main() {
    string s = "Hello";
    cout << "下标遍历: ";
    for (int i = 0; i < s.length(); i++) {
        cout << s[i] << "-";
    }
    cout << endl;
    cout << "范围遍历: ";
    for (char c : s) {
        cout << c << " ";
    }
    cout << endl;
    int cnt = 0;
    for (char c : s) {
        if (c == 'l') cnt++;
    }
    cout << "'l' count = " << cnt << endl;
    return 0;
}

